mapper.update:
UPDATE store
SET holiday = #{holiday},
    notice = #{notice},
    state = #{state}
WHERE store_id = #{storeId}

mapper.select:
SELECT o.order_id AS orderId, o.user_no AS userNo, o.order_time AS orderDate, o.amount AS totalPrice, o.order_state AS state, GROUP_CONCAT(od.menu_name SEPARATOR ', ') AS menuList FROM orders o JOIN order_detail od ON o.order_id = od.order_id WHERE o.store_id = #{storeId}
AND o.order_state = #{state}
GROUP BY o.order_id ORDER BY o.order_time DESC

mapper.update:
UPDATE orders
SET order_state = #{orderState}
WHERE order_id = #{orderId}

UPDATE menu
SET name = #{name},
    menu_info = #{menuInfo},
    price = #{price},
    menu_pic = #{menuPic}
WHERE menu_id = #{menuId}

mapper.insert:
INSERT INTO store_category (store_id, category_id)
SELECT store_id, #{categoryId}
FROM store
WHERE owner_id = #{userId}
ORDER BY store_id DESC
    LIMIT 1
